const aiResponse = $input.first().json;
const text = aiResponse.text || JSON.stringify(aiResponse);

// Parse JSON from AI response
let transactions = [];
try {
  const jsonMatch = text.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    transactions = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  return [{ json: { error: 'Failed to parse transactions', raw: text } }];
}

if (transactions.length === 0) {
  return [{ json: { message: 'No new transactions found', count: 0 } }];
}

// Generate unique IDs and add metadata
const now = new Date().toISOString();
const processed = transactions.map((txn, i) => ({
  txn_id: `txn_${Date.now()}_${i}`,
  date: txn.date || '',
  amount: txn.amount || 0,
  merchant: txn.merchant || 'Unknown',
  category: txn.category || 'other',
  type: txn.type || 'debit',
  source: txn.source || 'bank',
  card_name: txn.card_name || '',
  description: txn.description || '',
  email_account: 'auto_scan',
  raw_email_id: '',
  created_at: now
}));

return processed.map(t => ({ json: t }));

const newTxns = $('Process Transactions').all().map(t => t.json);
const existing = $('Read Existing Transactions').all().map(t => t.json);

// Create signature set from existing transactions
const existingSigs = new Set(
  existing.map(t => `${t.date}_${t.merchant}_${t.amount}`)
);

// Filter out duplicates
const unique = newTxns.filter(t => {
  const sig = `${t.date}_${t.merchant}_${t.amount}`;
  if (existingSigs.has(sig)) return false;
  existingSigs.add(sig); // Also dedup within batch
  return true;
});

if (unique.length === 0) {
  return [{ json: { message: 'All transactions already exist', count: 0, unique: [] } }];
}

return [{ json: { count: unique.length, unique } }];
